def color_wipe(color, delay=0.1):
    matrix.fill(0)
    for i in range(MATRIX_WIDTH):
        for j in range(MATRIX_HEIGHT):
            matrix.pixel(i, j, color)
            matrix.show()
            time.sleep(delay)
    matrix.fill(0)

# 调用示例
color_wipe(NeopixelMatrix.COLOR_GREEN)

