def animate_images(matrix, frames, delay=0.5):
    while True:
        for frame in frames:
            matrix.show_rgb565_image(frame)
            matrix.show()
            time.sleep(delay)

# 调用示例
animate_images(matrix, animation_frames, delay=0.5)
